const fs = require('node:fs');
const path = require('node:path');

const rootDir = path.resolve(__dirname, '..');
const sourcePath = path.join(rootDir, 'catalog', 'default-capability-catalog.json');
const outputDir = path.join(rootDir, 'src', 'activation', 'generated');
const outputPath = path.join(outputDir, 'defaultCapabilityCatalog.ts');

const raw = fs.readFileSync(sourcePath, 'utf8');
const parsed = JSON.parse(raw);

const banner = [
  '// This file is generated by scripts/generate-capability-catalog.js.',
  '// Do not edit it by hand; update catalog/default-capability-catalog.json instead.',
  '',
].join('\n');

const body = `${banner}export const DEFAULT_ACTIVATION_CAPABILITY_CATALOG = ${JSON.stringify(parsed, null, 2)} as const;\n`;

fs.mkdirSync(outputDir, { recursive: true });
fs.writeFileSync(outputPath, body, 'utf8');
